import{MarketplaceApi}from"./api";import{PageRoutes}from"./routes";function byId(e){return document.getElementById(e)}function escapeHtml(e){return String(e??"").replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;").replace(/'/g,"&#39;")}function normalizePortfolio(e){return{tagline:e.tagline??"",summary:e.summary??"",location:e.location??"",availability:e.availability??"",skills:e.skills??[],projects:e.projects??[],links:e.links??[]}}function parseSkills(e){return e.split(",").map((e=>e.trim())).filter((e=>e.length>0))}function projectFields(e){return[0,1,2].map((a=>e[a]??{title:"",summary:"",tech:"",imageUrl:""})).map(((e,a)=>`\n    <div class="card">\n      <h3>Project ${a+1}</h3>\n      <label class="form-field" for="project-title-${a}">\n        <span>Title</span>\n        <input id="project-title-${a}" class="form-input" value="${escapeHtml(e.title)}" />\n      </label>\n      <label class="form-field" for="project-tech-${a}">\n        <span>Tech</span>\n        <input id="project-tech-${a}" class="form-input" value="${escapeHtml(e.tech)}" />\n      </label>\n      <label class="form-field" for="project-image-${a}">\n        <span>Image URL</span>\n        <input id="project-image-${a}" class="form-input" value="${escapeHtml(e.imageUrl)}" />\n      </label>\n      <label class="form-field" for="project-summary-${a}">\n        <span>Summary</span>\n        <textarea id="project-summary-${a}" class="form-input form-textarea">${escapeHtml(e.summary)}</textarea>\n      </label>\n    </div>\n  `)).join("")}function renderPortfolioPage(e,a){return MarketplaceApi.freelancerPortfolio(e).then((e=>{const n=normalizePortfolio(e.portfolio),l=n.skills.map((e=>`<span class="badge badge-blue">${escapeHtml(e)}</span>`)).join(""),t=n.projects.map((e=>{const a=escapeHtml(e.imageUrl);return`\n        <article class="sexy-card">\n          <div class="sexy-card-bg" ${a?`style="background-image:url('${a}');"`:'style="background: linear-gradient(135deg, rgba(41,121,255,0.25), rgba(0,229,255,0.1));"'}></div>\n          <div class="card-content">\n            <h3>${escapeHtml(e.title)}</h3>\n            <p>${escapeHtml(e.summary)}</p>\n            <div class="badge badge-blue">${escapeHtml(e.tech)}</div>\n          </div>\n        </article>\n      `})).join(""),s=n.links.map((e=>`<a class="btn btn-ghost btn-sm" href="${escapeHtml(e.url)}" target="_blank" rel="noopener noreferrer">${escapeHtml(e.label)}</a>`)).join("");a.innerHTML=`\n      <section class="profile-header">\n        <div class="container">\n          <span class="badge badge-blue">Freelancer</span>\n          <h1>${escapeHtml(e.displayName)}</h1>\n          <p>${escapeHtml(n.tagline)}</p>\n          <div class="profile-stats">\n            <span>${escapeHtml(e.headline)}</span>\n            <span>$${escapeHtml(e.hourlyRate)}/hr</span>\n            <span>${escapeHtml(n.location)}</span>\n            <span>${escapeHtml(n.availability)}</span>\n          </div>\n        </div>\n      </section>\n      <section class="section">\n        <div class="container grid-2">\n          <article class="card">\n            <h2>About This Freelancer</h2>\n            <p>${escapeHtml(n.summary)}</p>\n            <h3>Skills</h3>\n            <div class="tag-list">${l}</div>\n          </article>\n          <article class="card">\n            <h2>Links</h2>\n            <div style="display:flex; gap:10px; flex-wrap:wrap;">${s}</div>\n          </article>\n        </div>\n      </section>\n      <section class="section">\n        <div class="container">\n          <h2>Selected Work</h2>\n          <div class="grid-3">${t}</div>\n        </div>\n      </section>\n    `}))}async function renderFreelancerWorkspace(e){let a=await MarketplaceApi.freelancerWorkspace();const n=()=>{const l=normalizePortfolio(a.portfolio),t=a.talentProfile?.headline??"",s=a.talentProfile?.hourlyRate??0,r=(a.talentProfile?.skills??[]).join(", ");if(!a.activated){e.innerHTML=`\n        <section class="card">\n          <h2>Activate Freelancer Account</h2>\n          <p class="form-status">\n            Your account is currently <strong>${escapeHtml(a.role)}</strong>.\n            Activate freelancer mode to generate your public portfolio page and edit it here.\n          </p>\n          <div class="form-actions">\n            <button class="btn btn-accent" id="activate-workspace-btn">Activate + Generate Page</button>\n          </div>\n        </section>\n      `;const l=byId("activate-workspace-btn");return void l?.addEventListener("click",(async()=>{l.setAttribute("disabled","true"),a=await MarketplaceApi.activateFreelancerWorkspace(),n()}))}e.innerHTML=`\n      <section class="card">\n        <h2>Freelancer Page Workspace</h2>\n        <p class="form-status">Generated page: <a href="${escapeHtml(a.portfolioUrl)}" target="_blank" rel="noopener noreferrer">${escapeHtml(a.portfolioUrl)}</a></p>\n        <div class="form-actions">\n          <a class="btn btn-ghost btn-sm" href="${escapeHtml(a.portfolioUrl)}" target="_blank" rel="noopener noreferrer">Open My Public Portfolio</a>\n        </div>\n      </section>\n      <section class="card form-shell">\n        <h3>Portfolio Details</h3>\n        <div class="form-grid">\n          <label class="form-field" for="workspace-display-name">\n            <span>Display Name</span>\n            <input id="workspace-display-name" class="form-input" value="${escapeHtml(a.displayName)}" />\n          </label>\n          <label class="form-field" for="workspace-headline">\n            <span>Headline</span>\n            <input id="workspace-headline" class="form-input" value="${escapeHtml(t)}" />\n          </label>\n          <label class="form-field" for="workspace-rate">\n            <span>Hourly Rate (USD)</span>\n            <input id="workspace-rate" class="form-input" type="number" min="0" step="1" value="${escapeHtml(s)}" />\n          </label>\n          <label class="form-field" for="workspace-location">\n            <span>Location</span>\n            <input id="workspace-location" class="form-input" value="${escapeHtml(l.location)}" />\n          </label>\n          <label class="form-field" for="workspace-availability">\n            <span>Availability</span>\n            <input id="workspace-availability" class="form-input" value="${escapeHtml(l.availability)}" />\n          </label>\n          <label class="form-field" for="workspace-tagline">\n            <span>Tagline</span>\n            <input id="workspace-tagline" class="form-input" value="${escapeHtml(l.tagline)}" />\n          </label>\n        </div>\n        <label class="form-field" for="workspace-skills">\n          <span>Skills (comma separated)</span>\n          <input id="workspace-skills" class="form-input" value="${escapeHtml(r)}" />\n        </label>\n        <label class="form-field" for="workspace-summary">\n          <span>About Summary</span>\n          <textarea id="workspace-summary" class="form-input form-textarea">${escapeHtml(l.summary)}</textarea>\n        </label>\n        <div class="project-grid">\n          ${projectFields(l.projects)}\n        </div>\n        <div class="form-actions">\n          <button class="btn btn-accent" id="workspace-save-btn">Save Portfolio</button>\n          <span id="workspace-status" class="form-status"></span>\n        </div>\n      </section>\n    `;const i=byId("workspace-save-btn"),c=byId("workspace-status");i?.addEventListener("click",(async()=>{i.setAttribute("disabled","true"),c&&(c.textContent="Saving...");const e=byId("workspace-display-name")?.value??"",l=byId("workspace-headline")?.value??"",t=Number(byId("workspace-rate")?.value??0),s=byId("workspace-location")?.value??"",r=byId("workspace-availability")?.value??"",o=byId("workspace-tagline")?.value??"",p=byId("workspace-summary")?.value??"",d=parseSkills(byId("workspace-skills")?.value??""),m=[0,1,2].map((e=>({title:byId(`project-title-${e}`)?.value??"",tech:byId(`project-tech-${e}`)?.value??"",imageUrl:byId(`project-image-${e}`)?.value??"",summary:byId(`project-summary-${e}`)?.value??""}))).filter((e=>e.title.trim().length>0)),u={displayName:e,headline:l,hourlyRate:Number.isFinite(t)?t:0,skills:d,portfolio:{tagline:o,summary:p,location:s,availability:r,skills:d,projects:m,links:a.portfolio.links}};a=await MarketplaceApi.saveFreelancerWorkspace(u),c&&(c.textContent="Saved."),i.removeAttribute("disabled"),n()}))};n()}export async function hydratePage(e){if("hire-direct"!==e)if("portfolios"!==e)if("freelancer"!==e)if("client-dashboard"!==e)if("freelancer-dashboard"!==e){if("freelancer-portfolio"===e){const e=byId("freelancer-portfolio-root");if(!e)return;const a=Number(document.body.dataset.freelancerUserId??"");if(!Number.isFinite(a))return void(e.innerHTML='<article class="card"><h2>Invalid Freelancer</h2><p>Unable to locate this freelancer profile.</p></article>');await renderPortfolioPage(a,e)}}else{const e=byId("freelancer-dashboard-root");if(!e)return;await renderFreelancerWorkspace(e)}else{const e=byId("client-dashboard-root");if(!e)return;const a=await MarketplaceApi.clientDashboard();e.textContent=JSON.stringify(a,null,2)}else{const e=byId("freelancer-jobs");if(!e)return;const a=await MarketplaceApi.fundedJobs();e.innerHTML=a.map((e=>`<article class="card scroll-reveal">\n        <span class="badge badge-fund">Funded</span>\n        <h3>${escapeHtml(e.title)}</h3>\n        <p>${escapeHtml(e.domain)}</p>\n        <p class="mono">Escrow: $${escapeHtml(e.escrowBalance)}</p>\n      </article>`)).join("")}else{const e=byId("portfolio-grid");if(!e)return;const a=await MarketplaceApi.portfolios();e.innerHTML=a.map((e=>{const a=escapeHtml(e.coverImage);return`\n        <article class="sexy-card scroll-reveal">\n          <div class="sexy-card-bg" style="${a?`background-image:url('${a}');`:"background: linear-gradient(135deg, rgba(41,121,255,0.25), rgba(0,229,255,0.1));"}"></div>\n          <div class="card-content">\n            <h3>${escapeHtml(e.domain)}</h3>\n            <p>${escapeHtml(e.totalProjects)} completed projects</p>\n            <span class="badge badge-fund">Funded Work</span>\n          </div>\n        </article>\n      `})).join("")}else{const e=byId("hire-direct-list");if(!e)return;const a=await MarketplaceApi.hireDirect();e.innerHTML=a.map((e=>`<article class="card scroll-reveal">\n        <span class="badge badge-blue">Top Rated</span>\n        <h3>${escapeHtml(e.name)}</h3>\n        <p>${escapeHtml(e.headline??"")}</p>\n        <p class="mono">$${escapeHtml(e.hourlyRate)}/hr</p>\n        <p class="small">${escapeHtml(e.skills.join(", "))}</p>\n        <a class="btn btn-ghost btn-sm" href="${PageRoutes.freelancerPortfolio(e.userId)}">View Portfolio</a>\n      </article>`)).join("")}}